# Build the JSON items per schema
def classify_and_build(c):
    span_start = c['start']
    span_end = c['end']
    span_text = c['text']
    label = c['label']
    # Determine type
    if label.startswith('quran_') or (label == 'double_quoted' and 'تَحْسَبَن' in span_text) or (label=='double_quoted' and 'والذين' in span_text):
        citation_type = 'Aya'
    elif label in ('double_quoted', 'double_parentheses') or label.startswith('hadith'):
        citation_type = 'Hadeeth'
    else:
        # Heuristic: if contains 'الله' and verbs like قال:
        citation_type = 'Hadeeth'
    # Now references
    aya_reference = {}
    hadeeth_reference = {}
    if citation_type == 'Aya':
        # Determine which ayah
        txt = span_text
        if 'تَحْسَبَن' in txt or 'تَحْسَبَنَّ' in txt or 'تحسبن' in txt:
            # 3:169
            aya_reference = {'sura_name':'آل عمران','sura_number':3,'aya_number':169}
        elif txt.strip().startswith('فَرِحِينَ'):
            aya_reference = {'sura_name':'آل عمران','sura_number':3,'aya_number':170}
        elif txt.strip().startswith('يَسْتَبْشِرُونَ'):
            # Could be 3:171
            aya_reference = {'sura_name':'آل عمران','sura_number':3,'aya_number':171}
        elif txt.strip().startswith('وَالَّذِينَ هَاجَرُوا'):
            aya_reference = {'sura_name':'الحج','sura_number':22,'aya_number':58}
        elif txt.strip().startswith('ومن يخرج من بيته مهاجرًا') or txt.strip().startswith('وَمَن يَخْرُجْ'):
            aya_reference = {'sura_name':'النساء','sura_number':4,'aya_number':100}
        elif txt.strip().startswith('والذين قتلوا ثم ماتوا'):
            # paraphrase of 22:58
            aya_reference = {'sura_name':'الحج','sura_number':22,'aya_number':58}
        else:
            aya_reference = {}
    else:
        # hadith
        t = span_text
        # Determine likely collection
        col = None
        if 'مائة درجة' in t:
            col = 'Sahih Bukhari'
        elif 'أرواح الشهداء' in t or 'لما أصيب إخوانكم بأحد' in t:
            col = 'Sunan Abu Dawud'
        elif 'يغفر لهم كل ذنب' in t:
            col = 'Sahih Muslim' # referencing 'يغفر للشهيد كل شيء إلا الدين'
        elif 'للشهيد عند الله ست خصال' in t:
            col = 'Jami at-Tirmidhi'
        elif 'من سأل الله الشهادة' in t:
            col = 'Sahih Muslim'
        elif 'من قتل دون دمه' in t:
            col = 'Sunan Abu Dawud'
        elif 'من قاتل لتكون كلمة الله' in t:
            col = 'Sahih Bukhari'
        elif 'أنت من الأولين' in t:
            col = 'Sahih Muslim'
        else:
            col = None
        if col:
            hadeeth_reference = {'collection_name': col}
        else:
            hadeeth_reference = {}
    # Validation
    is_valid = False
    corrected_text = 'خطأ'
    completely_invalid = True
    return {
        'span_start': span_start,
        'span_end': span_end,
        'span_text': span_text,
        'citation_type': citation_type,
        'is_valid': is_valid,
        'aya_reference': aya_reference if citation_type=='Aya' else {},
        'hadeeth_reference': hadeeth_reference if citation_type=='Hadeeth' else {},
        'corrected_text': corrected_text,
        'completely_invalid': completely_invalid
    }

items = [classify_and_build(c) for c in citations]

